import{_ as t,o as i,c as l,ag as s}from"./chunks/framework.NIzFHKo_.js";const y=JSON.parse('{"title":"QiAccess Start Blueprint","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/60_knowledge/90_superseded_sources/qiaccess_start_blueprint.md","filePath":"10_core/60_knowledge/90_superseded_sources/qiaccess_start_blueprint.md"}'),a={name:"10_core/60_knowledge/90_superseded_sources/qiaccess_start_blueprint.md"};function o(r,e,d,n,c,u){return i(),l("div",null,[...e[0]||(e[0]=[s('<h1 id="qiaccess-start-blueprint" tabindex="-1">QiAccess Start Blueprint <a class="header-anchor" href="#qiaccess-start-blueprint" aria-label="Permalink to &quot;QiAccess Start Blueprint&quot;">​</a></h1><p>QiAccess Start is Cody&#39;s cognitive front door.</p><p>It has seven roots only:</p><ol><li>Home</li><li>Start</li><li>Capture</li><li>Knowledge</li><li>Memory</li><li>Insights</li><li>System</li></ol><h2 id="root-intent" tabindex="-1">Root intent <a class="header-anchor" href="#root-intent" aria-label="Permalink to &quot;Root intent&quot;">​</a></h2><ul><li><code>Home</code>: orient the day and expose the shortest useful paths</li><li><code>Start</code>: open tools, services, projects, and working surfaces</li><li><code>Capture</code>: get thoughts, links, reminders, observations, and files into an intake path fast</li><li><code>Knowledge</code>: link to manuals, Wiki.js, repo docs, and reference material</li><li><code>Memory</code>: timeline, decisions, and context surfaces once ingestion exists</li><li><code>Insights</code>: summaries, pattern detection, reports, and future analysis layers</li><li><code>System</code>: nested admin, private-only tools, diagnostics, storage, and doctrine</li></ul><h2 id="system-subroutes" tabindex="-1">System subroutes <a class="header-anchor" href="#system-subroutes" aria-label="Permalink to &quot;System subroutes&quot;">​</a></h2><p>System owns:</p><ul><li><code>/system/access</code></li><li><code>/system/server</code></li><li><code>/system/storage</code></li><li><code>/system/integrations</code></li><li><code>/system/settings</code></li><li><code>/system/blueprint</code></li><li><code>/system/roadmap</code></li><li><code>/system/security</code></li><li><code>/system/diagnostics</code></li></ul><h2 id="current-phase" tabindex="-1">Current phase <a class="header-anchor" href="#current-phase" aria-label="Permalink to &quot;Current phase&quot;">​</a></h2><p>Phase 1 is stabilization and prototype flow validation:</p><ul><li>fix the SPA build</li><li>align the current app to the seven roots</li><li>preserve working launcher and link behavior</li><li>freeze legacy surfaces in place</li><li>validate Capture as the first real operational path</li></ul><h2 id="phase-0-—-freeze-and-protect-qinexus" tabindex="-1">Phase 0 — Freeze and protect (QiNexus) <a class="header-anchor" href="#phase-0-—-freeze-and-protect-qinexus" aria-label="Permalink to &quot;Phase 0 — Freeze and protect (QiNexus)&quot;">​</a></h2><p>Goal: prevent accidental loss during reorganization.</p><p><strong>Mandatory Rules:</strong></p><ul><li>Do not delete anything.</li><li>Do not let an AI move files directly.</li><li>Create and use the <code>130_system/qinexus_cleanup</code> folder.</li><li>Generate manifests and reports before any moves.</li></ul><h3 id="cleanup-system-structure" tabindex="-1">Cleanup System Structure <a class="header-anchor" href="#cleanup-system-structure" aria-label="Permalink to &quot;Cleanup System Structure&quot;">​</a></h3><p>Located at <code>G:\\My Drive\\QiNexus\\130_system\\qinexus_cleanup</code>:</p><ul><li><code>rules/</code>: Governance and movement criteria.</li><li><code>reports/</code>: Audit results and analysis.</li><li><code>manifests/</code>: Snapshots of directory state.</li><li><code>quarantine/</code>: Staging for disputed or risky items.</li><li><code>scripts/</code>: Automation for audit and verification.</li><li><code>approved_moves/</code>: Verified move instructions for human execution.</li></ul><h2 id="daily-use-priority" tabindex="-1">Daily-use priority <a class="header-anchor" href="#daily-use-priority" aria-label="Permalink to &quot;Daily-use priority&quot;">​</a></h2><p>The shortest path to daily use is:</p><ol><li>Start opens tools</li><li>Capture reduces friction</li><li>Knowledge points to real docs</li><li>System keeps private infrastructure visible</li><li>Storage shows QiNexus targets</li><li>Memory and Insights remain honest placeholders</li><li>Paperless ingestion becomes the first proven intake pipeline</li></ol><h2 id="qinexus-root-bands-doctrine" tabindex="-1">QiNexus Root Bands (Doctrine) <a class="header-anchor" href="#qinexus-root-bands-doctrine" aria-label="Permalink to &quot;QiNexus Root Bands (Doctrine)&quot;">​</a></h2><p>The directory structure is organized into numeric bands to maintain priority and categorization:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Band</th><th style="text-align:left;">Root</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;">00</td><td style="text-align:left;"><code>00_inbox</code></td><td style="text-align:left;">Temporary intake and staging</td></tr><tr><td style="text-align:left;">10</td><td style="text-align:left;"><code>10_workbench</code></td><td style="text-align:left;">Active projects, tasks, and drafts</td></tr><tr><td style="text-align:left;">20</td><td style="text-align:left;"><code>20_timeline</code></td><td style="text-align:left;">Journals, logs, and chronological records</td></tr><tr><td style="text-align:left;">30</td><td style="text-align:left;"><code>30_life</code></td><td style="text-align:left;">Routines, wellness, personal operations</td></tr><tr><td style="text-align:left;">40</td><td style="text-align:left;"><code>40_people</code></td><td style="text-align:left;">Family, Mom&#39;s Care, relationships</td></tr><tr><td style="text-align:left;">50</td><td style="text-align:left;"><code>50_business</code></td><td style="text-align:left;">Client work, branding, revenue systems</td></tr><tr><td style="text-align:left;">60</td><td style="text-align:left;"><code>60_finance</code></td><td style="text-align:left;">Bills, budgets, accounts, reports</td></tr><tr><td style="text-align:left;">70</td><td style="text-align:left;"><code>70_legal</code></td><td style="text-align:left;">Case files, court filings, evidence</td></tr><tr><td style="text-align:left;">80</td><td style="text-align:left;"><code>80_tech</code></td><td style="text-align:left;">Apps, server configs, architecture</td></tr><tr><td style="text-align:left;">90</td><td style="text-align:left;"><code>90_assets</code></td><td style="text-align:left;">Media, design templates, branding assets</td></tr><tr><td style="text-align:left;">100</td><td style="text-align:left;"><code>100_data</code></td><td style="text-align:left;">Datasets, exports, CSV/JSON storage</td></tr><tr><td style="text-align:left;">110</td><td style="text-align:left;"><code>110_reference</code></td><td style="text-align:left;">Laws, guides, external research</td></tr><tr><td style="text-align:left;">120</td><td style="text-align:left;"><code>120_archive</code></td><td style="text-align:left;">Frozen, inactive, and legacy records</td></tr><tr><td style="text-align:left;">130</td><td style="text-align:left;"><code>130_system</code></td><td style="text-align:left;">Manifests, rules, indexes, automation</td></tr></tbody></table>',25)])])}const f=t(a,[["render",o]]);export{y as __pageData,f as default};
